    graph_copy = copy.deepcopy(graph_data)
    target_node_name = 'ju1.a4.m2'
    target_node_id = None

    # Find the target AGG_BLOCK node
    for node in graph_copy.nodes(data=True):
        if node[1].get('name') == target_node_name and 'EK_AGG_BLOCK' in node[1].get('type', []):
            target_node_id = node[0]
            break

    if not target_node_id:
        return_object = {
            'type': 'list',
            'data': [],
            'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
        }
        return return_object

    # Get children (PACKET_SWITCH) of the AGG_BLOCK
    children = []
    for edge in graph_copy.out_edges(target_node_id, data=True):
        src, dst, attr = edge
        if 'RK_CONTAINS' in attr.get('type', []) or ('type' in attr and attr['type'] == 'RK_CONTAINS'):
            dst_attr = graph_copy.nodes[dst]
            if 'EK_PACKET_SWITCH' in dst_attr.get('type', []):
                children.append(dst)

    # For each PACKET_SWITCH, calculate total capacity from PORTs
    result_list = []
    for ps_node_id in children:
        ps_attr = graph_copy.nodes[ps_node_id]
        ps_name = ps_attr.get('name', ps_node_id)
        total_capacity = 0

        # Traverse PORTs under PACKET_SWITCH
        for e in graph_copy.out_edges(ps_node_id, data=True):
            _, port_node_id, edge_attr = e
            if 'RK_CONTAINS' in edge_attr.get('type', []) or (edge_attr.get('type') == 'RK_CONTAINS'):
                port_attr = graph_copy.nodes[port_node_id]
                if 'EK_PORT' in port_attr.get('type', []):
                    total_capacity += port_attr.get('physical_capacity_bps', 0)

        result_list.append((ps_name, total_capacity))

    # Sort by capacity descending
    result_list.sort(key=lambda x: x[1], reverse=True)

    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)
    return_object = {
        'type': 'list',
        'data': result_list,
        'updated_graph': graph_json
    }
    return return_object

