    graph_copy.add_node('new_EK_PORT_39', type=['EK_PORT'], physical_capacity_bps=1000)
    graph_copy.add_edge('ju1.a1.m4.s2c7', 'new_EK_PORT_39', type=['RK_CONTAINS'])
    # Now, count the number of EK_PORT nodes in ju1.a1.m4.s2c7 in the updated graph
    count = 0
    for node in graph_copy.nodes(data=True):
        if 'EK_PORT' in node[1]['type']:
            # Find predecessors to see if ju1.a1.m4.s2c7 is an ancestor
            predecessors = nx.ancestors(graph_copy.to_undirected(), node[0])
            predecessor_names = [graph_copy.nodes[n].get('name') for n in predecessors if graph_copy.nodes.get(n)]
            if any(name and name.startswith('ju1.a1.m4.s2c7') for name in predecessor_names):
                count += 1
    # Considering direct containment as well (more robust check)
    # Let's reevaluate by exploring from ju1.a1.m4.s2c7 downward
    def get_all_port_descendants(graph, root_name):
        root_node_id = None
        for node in graph.nodes(data=True):
            if node[1].get('name') == root_name:
                root_node_id = node[0]
                break
        if not root_node_id:
            return 0
        count = 0
        queue = [root_node_id]
        visited = set()
        while queue:
            current = queue.pop(0)
            if current in visited:
                continue
            visited.add(current)
            for successor in graph.successors(current):
                edge_data = graph.get_edge_data(current, successor)
