                    node_data = graph.nodes[successor]
                    if 'EK_PORT' in node_data.get('type', []):
                        count += 1
                    else:
                        queue.append(successor)
        return count
    port_count = get_all_port_descendants(graph_copy, 'ju1.a1.m4.s2c7')
    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)
